module clock_gate(
  input CLK, // clock signal
  input EN, // enable signal
  input TE, // test enable signal
  output ENCLK // gated clock signal
);

  reg ungated_clk;

  always @(*) begin
    if (TE) begin
      ungated_clk = 1;
    end else if (EN) begin
      ungated_clk = CLK;
    end else begin
      ungated_clk = 0;
    end
  end

  assign ENCLK = ungated_clk;

endmodule
